reserve(token: string, entityType: string, entityId: string, ttlMs?: number): void {
  const key = entityKey(entityType, entityId);
  const ttl = ttlMs ?? cacheConfig.defaultTtl;

  // Map token to entity key (forward-only: old tokens remain)
  tokenIndex.set(token, key, ttl);

  // Invalidate stale data — set null (reserved, not enriched)
  cache.set(key, null, ttl);
}

invalidateByEntity(entityType: string, entityId: string): boolean {
  const key = entityKey(entityType, entityId);
  const existed = cache.has(key);

  if (existed) {
    cache.delete(key);
    entityCacheMetrics.recordInvalidation(1);
    return true;
  }

  return false;
}

function registerCacheInvalidation(): void {
  if (isRegistered) {
    logEvent(null, 'warn', 'Cache hook already registered');
    return;
  }

  activityBus.onAny(handleActivityEvent);
  isRegistered = true;

  logEvent(null, 'info', 'Entity cache hook registered');
}

invalidateAuthCacheByUser = (userId: string): void => {
  // Invalidate all session entries
  const sessionIds = userIndex.get(userId);
  if (sessionIds) {
    for (const sessionId of sessionIds) {
      sessionCache.delete(sessionId);
    }
    userIndex.delete(userId);
  }
  // Invalidate membership entry
  membershipCache.delete(userId);
}

async function getAttachmentOp(ctx: AuthContext, id: string) {
  const { entity: attachment } = await getValidProductEntity(ctx, id, 'attachment', 'read');

  // withAuditUser queries users (no RLS), findAttachmentViewCount queries counters (no RLS)
  const attachmentResponse = await withAuditUser(ctx, attachment);
  const viewCount = await findAttachmentViewCount(ctx, { entityId: id });

  const data = { ...attachmentResponse, viewCount };
  return { success: true, data } as OperationResult<typeof data>;
}

transformNotification: (notification, subscriber) => {
  // Sign cache token per subscriber session
  if (notification.cacheToken) {
    return { ...notification, cacheToken: signCacheToken(notification.cacheToken, subscriber.sessionToken) };
  }
  return notification;
}

async function getEntityByTransaction(stxId: string): Promise<EntityReference | null> {
  const [activity] = await findActivityRefByMutationId.execute({ mutationId: stxId });

  // entityType and subjectId are nullable in schema, narrow before returning
  if (!activity?.entityType || !activity?.subjectId) return null;
  return { entityType: activity.entityType, subjectId: activity.subjectId };
}

protected getDomainName(event: E): string | undefined {
  if (event.requestContext && 'domainName' in event.requestContext) {
    return event.requestContext.domainName
  }

  const hostFromHeaders = this.getHeaderValue(event.headers, 'host')

  if (hostFromHeaders) {
    return hostFromHeaders
  }

  const multiValueHeaders = 'multiValueHeaders' in event ? event.multiValueHeaders : {}
  const hostFromMultiValueHeaders = this.getHeaderValue(multiValueHeaders, 'host')

  return hostFromMultiValueHeaders
}

message(ws, message) {
  const websocketListeners = ws.data.events
  if (websocketListeners.onMessage) {
    const normalizedReceiveData: WSMessageReceive =
      typeof message === 'string' ? message : message.buffer

    websocketListeners.onMessage(createWSMessageEvent(normalizedReceiveData), createWSContext(ws))
  }
}

function detectFromPath(c: Context, options: DetectorOptions): string | undefined {
  const url = new URL(c.req.url)
  const pathSegments = url.pathname.split('/').filter(Boolean)
  const langSegment = pathSegments[options.lookupFromPathIndex]
  return normalizeLanguage(langSegment, options)
}

function validateOptions(options: DetectorOptions): void {
  if (!options.supportedLanguages.includes(options.fallbackLanguage)) {
    throw new Error('Fallback language must be included in supported languages')
  }

  if (options.lookupFromPathIndex < 0) {
    throw new Error('Path index must be non-negative')
  }

  if (!options.order.every((detector) => Object.keys(detectors).includes(detector))) {
    throw new Error('Invalid detector type in order array')
  }
}

function cacheLanguage(c: Context, language: string, options: DetectorOptions): void {
  if (!Array.isArray(options.caches) || !options.caches.includes('cookie')) {
    return
  }

  try {
    setCookie(c, options.lookupCookie, language, options.cookieOptions)
  } catch (error) {
    if (options.debug) {
      console.error('Failed to cache language:', error)
    }
  }
}

startTime = (c: Context, name: string, description?: string) => {
  const metrics = c.get('metric')
  if (!metrics) {
    console.warn('Metrics not initialized! Please add the `timing()` middleware to this route!')
    return
  }
  metrics.timers.set(name, { description, start: getTime() })
}

async function signing(
  privateKey: SignatureKey,
  alg: SignatureAlgorithm,
  data: BufferSource
): Promise<ArrayBuffer> {
  const algorithm = getKeyAlgorithm(alg)
  const cryptoKey = await importPrivateKey(privateKey, algorithm)
  return await crypto.subtle.sign(algorithm, cryptoKey, data)
}

async function verifying(
  publicKey: SignatureKey,
  alg: SignatureAlgorithm,
  signature: BufferSource,
  data: BufferSource
): Promise<boolean> {
  const algorithm = getKeyAlgorithm(alg)
  const cryptoKey = await importPublicKey(publicKey, algorithm)
  return await crypto.subtle.verify(algorithm, cryptoKey, signature, data)
}

function calculateExpiration(createdAt: number, updatedAt: number, duration: MaxAgeDuration) {
  if (duration.inactivity === undefined) {
    return createdAt + duration.absolute
  }

  return Math.min(updatedAt + duration.inactivity, createdAt + duration.absolute)
}

getStytchSession: (c: Context): Session => {
  const session = c.get('stytchSession')
  if (!session) {
    throw Error(
      'No session in context. Was Consumer.authenticateSessionLocal or Consumer.authenticateSessionRemote called?'
    )
  }
  return session
}

function validatePassword(password: string): string | null {
	if (!password || password.length < 8) {
		return 'Password must be at least 8 characters'
	}
	if (!/[a-z]/.test(password)) {
		return 'Password must contain a lowercase letter'
	}
	if (!/[A-Z]/.test(password)) {
		return 'Password must contain an uppercase letter'
	}
	if (!/[0-9]/.test(password)) {
		return 'Password must contain a number'
	}
	return null
}

function shouldRejectSeasonEpisodeMismatch(
	searcheeTitle: string,
	candidateTitle: string,
	candidateFiles: FileInfo[],
	includeSingleEpisodes: boolean
): boolean {
	if (includeSingleEpisodes) return false
	if (!isSeasonPack(searcheeTitle)) return false
	return isSingleEpisode(candidateTitle, candidateFiles)
}

